"use client";

import * as React from "react";
import {
  PageHeader,
  BottomActionBar,
  Button,
  RadioCardGroup,
  RadioCard,
  ToggleGroup,
  ToggleGroupItem,
  AmountBreakdown,
  Badge,
  Card,
  CardHeader,
  CardTitle,
  CardContent,
  MetadataList,
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
  formatCurrency,
} from "@gunjo/ui";
import { IconBus, IconMapPin, IconInfoCircle } from "@tabler/icons-react";
import {
  TICKET_TYPES,
  PASSENGERS,
  PAYMENTS,
  COVERAGE_AREAS,
  OPERATOR,
  fareFor,
  type TicketTypeId,
  type PassengerId,
  type PaymentId,
} from "./data";
import { ActiveTicket } from "./ActiveTicket";

// 券種ごとの有効分数（一日券は当日終バス想定で大きめ）
const VALID_MINUTES: Record<TicketTypeId, number> = {
  single: 120,
  oneday: 18 * 60,
  freepass: 24 * 60,
};

export default function BusTicketPage() {
  const [ticketId, setTicketId] = React.useState<TicketTypeId>("oneday");
  const [passenger, setPassenger] = React.useState<PassengerId>("adult");
  const [payment, setPayment] = React.useState<PaymentId>("ic");
  const [activated, setActivated] = React.useState(false);
  const [activatedAt, setActivatedAt] = React.useState<number | null>(null);

  const ticket = TICKET_TYPES.find((t) => t.id === ticketId)!;
  const passengerMeta = PASSENGERS.find((p) => p.id === passenger)!;
  const fare = fareFor(ticket.adultFare, passengerMeta.factor);

  // 整理番号（決定的・ハイドレーション安全）
  const code = React.useMemo(
    () => `NB-${ticketId.slice(0, 2).toUpperCase()}-${String(fare).padStart(4, "0")}-${passenger.slice(0, 1).toUpperCase()}`,
    [ticketId, fare, passenger]
  );

  function handleBuyOrActivate() {
    // 購入 → 利用開始（アクティブ化）。デモのため即時にアクティブ化シートを開く。
    setActivatedAt(Date.now());
    setActivated(true);
  }

  return (
    <div className="mx-auto flex min-h-dvh w-full max-w-md flex-col bg-background">
      <PageHeader
        title="モバイル乗車券"
        subtitle={OPERATOR.name}
        onBack={() => history.back()}
        actions={
          <Badge variant="secondary" icon={<IconBus className="size-3.5" />}>
            モバチケ
          </Badge>
        }
      />

      <main className="flex flex-1 flex-col gap-6 px-4 pb-6 pt-4">
        {/* 1. 券種の選択 */}
        <section aria-labelledby="sec-type">
          <h2 id="sec-type" className="mb-2 text-sm font-semibold text-foreground">
            券種を選ぶ
          </h2>
          <RadioCardGroup
            value={ticketId}
            onValueChange={(v) => setTicketId(v as TicketTypeId)}
            aria-label="券種の選択"
          >
            {TICKET_TYPES.map((t) => (
              <RadioCard
                key={t.id}
                value={t.id}
                title={t.name}
                description={t.summary}
                price={formatCurrency(t.adultFare)}
                tags={t.tag ? <Badge variant="info">{t.tag}</Badge> : undefined}
                highlight={t.highlight}
              />
            ))}
          </RadioCardGroup>
          <p className="mt-1 px-1 text-xs text-muted-foreground">価格は大人運賃。{ticket.validity}。</p>
        </section>

        {/* 2. きっぷの条件（人数区分 + 支払い） */}
        <section aria-labelledby="sec-cond" className="flex flex-col gap-4">
          <h2 id="sec-cond" className="text-sm font-semibold text-foreground">
            きっぷの条件
          </h2>

          <div>
            <p id="lbl-passenger" className="mb-1.5 text-xs font-medium text-muted-foreground">
              旅客区分
            </p>
            <ToggleGroup
              type="single"
              value={passenger}
              onValueChange={(v) => v && setPassenger(v as PassengerId)}
              disallowEmpty
              variant="outline"
              className="w-full justify-stretch [&>*]:flex-1"
              aria-labelledby="lbl-passenger"
            >
              {PASSENGERS.map((p) => (
                <ToggleGroupItem key={p.id} value={p.id} aria-label={`${p.label}（${p.note}）`}>
                  {p.label}
                </ToggleGroupItem>
              ))}
            </ToggleGroup>
            <p className="mt-1 text-xs text-muted-foreground">{passengerMeta.note}</p>
          </div>

          <div>
            <p id="lbl-payment" className="mb-1.5 text-xs font-medium text-muted-foreground">
              支払い方法
            </p>
            <ToggleGroup
              type="single"
              value={payment}
              onValueChange={(v) => v && setPayment(v as PaymentId)}
              disallowEmpty
              variant="outline"
              className="w-full justify-stretch [&>*]:flex-1"
              aria-labelledby="lbl-payment"
            >
              {PAYMENTS.map((p) => (
                <ToggleGroupItem key={p.id} value={p.id}>
                  {p.label}
                </ToggleGroupItem>
              ))}
            </ToggleGroup>
            <p className="mt-1 text-xs text-muted-foreground">{PAYMENTS.find((p) => p.id === payment)!.note}</p>
          </div>
        </section>

        {/* 3. 運賃 */}
        <section aria-labelledby="sec-fare">
          <h2 id="sec-fare" className="mb-2 text-sm font-semibold text-foreground">
            運賃
          </h2>
          <Card>
            <CardContent className="pt-4">
              <AmountBreakdown
                lines={[
                  {
                    label: `${ticket.faceName}（${passengerMeta.label} 1名）`,
                    amount: fare,
                    note: passenger === "adult" ? "均一運賃区間" : `${passengerMeta.note}`,
                  },
                ]}
                total={{ label: "お支払金額", amount: fare }}
                formula={`${ticket.faceName} × ${passengerMeta.label}1名 ＝ お支払金額（${
                  PAYMENTS.find((p) => p.id === payment)!.label
                }決済）`}
              />
            </CardContent>
          </Card>
        </section>

        {/* 4. 利用可能エリア・路線 */}
        <section aria-labelledby="sec-area">
          <h2 id="sec-area" className="mb-2 flex items-center gap-1.5 text-sm font-semibold text-foreground">
            <IconMapPin className="size-4 text-muted-foreground" aria-hidden="true" />
            利用可能エリア・系統
          </h2>
          <Card>
            <CardHeader className="pb-0">
              <CardTitle className="text-sm">{OPERATOR.lineName}</CardTitle>
            </CardHeader>
            <CardContent className="pt-3">
              <MetadataList
                layout="horizontal"
                items={COVERAGE_AREAS.map((a) => ({ label: a.name, value: a.lines }))}
              />
              <p className="mt-2 flex items-start gap-1.5 text-xs text-muted-foreground">
                <IconInfoCircle className="mt-0.5 size-3.5 shrink-0" aria-hidden="true" />
                高速・空港リムジン路線は対象外です。
              </p>
            </CardContent>
          </Card>
        </section>

        {/* 既に購入済みなら、券面を再表示する導線 */}
        {activated && activatedAt != null && (
          <Button variant="outline" onClick={() => setActivated(true)} aria-haspopup="dialog">
            購入済みの乗車券を表示
          </Button>
        )}
      </main>

      {/* 5. 購入 / 利用開始（永続ボトムバー） */}
      <BottomActionBar
        maxWidth="md"
        actions={
          <Button variant="primary" size="lg" className="min-h-12 px-6" onClick={handleBuyOrActivate}>
            {activatedAt == null ? "購入して利用を開始" : "利用を開始する"}
          </Button>
        }
      >
        <div>
          <p className="text-xs text-muted-foreground">{ticket.faceName}・{passengerMeta.label}1名</p>
          <p className="text-lg font-bold tabular-nums text-foreground">{formatCurrency(fare)}</p>
        </div>
      </BottomActionBar>

      {/* アクティブ化された券面（提示用） */}
      <Sheet open={activated} onOpenChange={setActivated}>
        <SheetContent side="bottom" className="max-h-[92dvh] overflow-y-auto">
          <SheetHeader>
            <SheetTitle>モバイル乗車券</SheetTitle>
            <SheetDescription>
              利用を開始しました。降車時にこの画面を乗務員へ提示してください。
            </SheetDescription>
          </SheetHeader>
          <div className="mt-4">
            {activatedAt != null && (
              <ActiveTicket
                ticket={ticket}
                passenger={passenger}
                activatedAt={activatedAt}
                validForMinutes={VALID_MINUTES[ticketId]}
                code={code}
              />
            )}
          </div>
        </SheetContent>
      </Sheet>
    </div>
  );
}

"use client";

import * as React from "react";
import { TicketStub, ExpiryBadge, Badge, Separator, Alert, AlertTitle, AlertDescription } from "@gunjo/ui";
import { IconBus, IconClockHour4 } from "@tabler/icons-react";
import { OPERATOR, type TicketType, type PassengerId } from "./data";
import { PASSENGERS } from "./data";

interface ActiveTicketProps {
  ticket: TicketType;
  passenger: PassengerId;
  /** アクティブ化した時刻（ms）。SSR一貫性のため親から渡す。 */
  activatedAt: number;
  /** 有効時間（分）。一日券などは終バスまでの分数を渡す。 */
  validForMinutes: number;
  /** 表示用の整理番号 */
  code: string;
}

/** mm:ss / hh:mm:ss の残り時間表記 */
function formatRemaining(ms: number): string {
  if (ms <= 0) return "00:00";
  const total = Math.floor(ms / 1000);
  const h = Math.floor(total / 3600);
  const m = Math.floor((total % 3600) / 60);
  const s = total % 60;
  const pad = (n: number) => String(n).padStart(2, "0");
  return h > 0 ? `${pad(h)}:${pad(m)}:${pad(s)}` : `${pad(m)}:${pad(s)}`;
}

export function ActiveTicket({ ticket, passenger, activatedAt, validForMinutes, code }: ActiveTicketProps) {
  const expiresAt = activatedAt + validForMinutes * 60_000;
  const passengerLabel = PASSENGERS.find((p) => p.id === passenger)?.label ?? "大人";

  // ライブ・カウントダウン。初期値はSSRと一致させるため activatedAt 起点で計算。
  const [now, setNow] = React.useState(activatedAt);
  React.useEffect(() => {
    setNow(Date.now());
    const id = window.setInterval(() => setNow(Date.now()), 1000);
    return () => window.clearInterval(id);
  }, []);

  const remainingMs = expiresAt - now;
  const expired = remainingMs <= 0;

  return (
    <div className="flex flex-col gap-4">
      <Alert variant={expired ? "destructive" : "info"}>
        <IconBus className="size-4" aria-hidden="true" />
        <AlertTitle>{expired ? "有効期限が切れました" : "乗車時に乗務員へ画面を提示してください"}</AlertTitle>
        <AlertDescription>
          {expired
            ? "この乗車券は失効しています。新しい乗車券をご購入ください。"
            : "降車時にこの画面を運転士へ。スクリーンショットは無効です。"}
        </AlertDescription>
      </Alert>

      <TicketStub value={code} format="qr" codeLabel={`整理番号 ${code}`}>
        <div className="flex flex-col gap-3">
          <div className="flex items-start justify-between gap-3">
            <div className="min-w-0">
              <p className="text-xs text-muted-foreground">{OPERATOR.name}</p>
              <p className="truncate text-lg font-bold text-foreground">{ticket.faceName}</p>
              <p className="truncate text-xs text-muted-foreground">{OPERATOR.lineName}</p>
            </div>
            <Badge variant={expired ? "destructive" : "success"}>{expired ? "失効" : "利用中"}</Badge>
          </div>

          <Separator />

          {/* 残り時間ヒーロー — モバイル乗車券の核 */}
          <div className="flex items-end justify-between gap-3">
            <div>
              <p className="flex items-center gap-1 text-xs text-muted-foreground">
                <IconClockHour4 className="size-3.5" aria-hidden="true" />
                有効時間 残り
              </p>
              <p
                className="text-3xl font-bold tabular-nums text-foreground"
                role="timer"
                aria-live="off"
                aria-label={`有効時間 残り ${formatRemaining(remainingMs)}`}
              >
                {formatRemaining(remainingMs)}
              </p>
            </div>
            <div className="text-right">
              <p className="text-xs text-muted-foreground">券種・きっぷの条件</p>
              <p className="text-sm font-medium text-foreground">{passengerLabel} ／ 1名</p>
            </div>
          </div>

          <div className="flex items-center justify-between">
            <span className="text-xs text-muted-foreground">有効期限</span>
            <ExpiryBadge value={new Date(expiresAt)} today={new Date(now)} showDate hideRemaining />
          </div>
        </div>
      </TicketStub>
    </div>
  );
}

// 路線バス モバイル乗車券 — ドメインデータ（西鉄バス想定のダミー値）
// SSR-safe: 関数を含まないプレーンなデータのみ。

export type TicketTypeId = "single" | "oneday" | "freepass";
export type PassengerId = "adult" | "child" | "disabled";
export type PaymentId = "ic" | "qr" | "credit";

export interface TicketType {
  id: TicketTypeId;
  name: string;
  /** 券面に出す短い種別名 */
  faceName: string;
  /** 大人運賃（円）。小児・障がい者は係数で算出 */
  adultFare: number;
  /** 説明（有効範囲・条件） */
  summary: string;
  /** 有効時間ラベル */
  validity: string;
  tag?: string;
  highlight?: string;
}

export const OPERATOR = {
  name: "西鉄バス",
  lineName: "天神〜博多駅 (均一運賃区間)",
} as const;

export const TICKET_TYPES: TicketType[] = [
  {
    id: "single",
    name: "普通乗車券（モバチケ）",
    faceName: "普通乗車券",
    adultFare: 190,
    summary: "天神〜博多エリアの均一運賃区間で1回乗車。乗車時に画面を乗務員へ提示。",
    validity: "アクティブ化から2時間 / 当日限り",
  },
  {
    id: "oneday",
    name: "一日乗車券（福岡市内）",
    faceName: "一日乗車券",
    adultFare: 700,
    summary: "福岡都心フリーエリアが1日乗り放題。3回以上の乗車でおトク。",
    validity: "利用開始当日の終バスまで有効",
    tag: "人気",
    highlight: "190円×4回ぶんでモト（3回乗ればおトク）",
  },
  {
    id: "freepass",
    name: "FUKUOKA 1DAY パス",
    faceName: "1DAY PASS",
    adultFare: 1800,
    summary: "福岡県内の主要路線・都市間バスを含む広域フリーパス。観光・遠出向け。",
    validity: "利用開始から24時間有効",
    highlight: "広域エリア（太宰府・海の中道方面まで）",
  },
];

export const PASSENGERS: { id: PassengerId; label: string; factor: number; note: string }[] = [
  { id: "adult", label: "大人", factor: 1, note: "中学生以上" },
  { id: "child", label: "小児", factor: 0.5, note: "小学生 / 半額・10円未満切上げ" },
  { id: "disabled", label: "障がい者", factor: 0.5, note: "手帳提示・割引運賃" },
];

export const PAYMENTS: { id: PaymentId; label: string; note: string }[] = [
  { id: "ic", label: "IC", note: "Suica / PASMO / nimoca 連携" },
  { id: "qr", label: "QR", note: "PayPay / d払い 等" },
  { id: "credit", label: "クレジット", note: "登録カードで決済" },
];

// 利用可能な系統・エリア（一日乗車券）
export const COVERAGE_AREAS = [
  { id: "tenjin", name: "天神地区", lines: "全系統（都心100円エリア含む）" },
  { id: "hakata", name: "博多駅地区", lines: "博多バスターミナル発着 全系統" },
  { id: "ohori", name: "大濠公園・福岡城", lines: "13 / 200 系統ほか" },
  { id: "momochi", name: "百道・福岡タワー", lines: "都市高速経由を除く一般路線" },
];

/** 小児・障がい者運賃：半額を10円単位に切上げ */
export function fareFor(adultFare: number, factor: number): number {
  if (factor === 1) return adultFare;
  return Math.ceil((adultFare * factor) / 10) * 10;
}
